/**
 * Main JavaScript
 *
 * Client-side functionality for Kiwi Shop Demo theme.
 * Generated by Kiwi Generator Phase 1
 *
 * @package kiwi-with-mock-data
 * @generated 2026-05-25T11:09:38.312154
 */

(function() {
	'use strict';

	// Wait for DOM ready
	document.addEventListener('DOMContentLoaded', function() {
		initMobileMenu();
		initAddToCart();
	});

	/**
	 * Initialize mobile menu toggle.
	 */
	function initMobileMenu() {
		const toggle = document.getElementById('mobile-menu-toggle');
		const nav = document.getElementById('site-navigation');

		if (!toggle || !nav) return;

		toggle.addEventListener('click', function() {
			nav.classList.toggle('hidden');
		});
	}

	/**
	 * Initialize add to cart buttons.
	 */
	function initAddToCart() {
		const buttons = document.querySelectorAll('.add-to-cart-btn');

		buttons.forEach(function(button) {
			button.addEventListener('click', function(e) {
				e.preventDefault();

				const productId = this.dataset.productId;
				const quantity = this.dataset.quantity || 1;

				addToCart(productId, quantity);
			});
		});
	}

	/**
	 * Add product to cart via AJAX.
	 *
	 * @param {number} productId Product ID.
	 * @param {number} quantity  Quantity.
	 */
	function addToCart(productId, quantity) {
		if (!window.wzTheme) {
			console.error('wzTheme not defined');
			return;
		}

		const data = new FormData();
		data.append('action', 'kiwi_with_mock_data_add_to_cart');
		data.append('product_id', productId);
		data.append('quantity', quantity);
		data.append('nonce', wzTheme.nonce);

		fetch(wzTheme.ajaxUrl, {
			method: 'POST',
			body: data
		})
		.then(response => response.json())
		.then(result => {
			if (result.success) {
				alert(result.data.message);
				// Update cart count in header
				updateCartCount(result.data.cart);
			} else {
				alert(result.data.message || 'Failed to add to cart');
			}
		})
		.catch(error => {
			console.error('Error:', error);
			alert('Failed to add to cart');
		});
	}

	/**
	 * Update cart count badge.
	 *
	 * @param {Object} cart Cart data.
	 */
	function updateCartCount(cart) {
		if (!cart || !cart.items) return;

		const count = cart.items.reduce((sum, item) => sum + item.quantity, 0);
		const badge = document.querySelector('.cart-count-badge');

		if (badge) {
			badge.textContent = count;
		}
	}

})();
